local ADDON_NAME, ns = ...
if GetLocale() ~= "frFR" then return end
local L = ns.L

L["%s only"] = "%s uniquement"
L["0 (professions only)"] = "0 (métiers seulement)"
L["About"] = "À propos"
L["Adds this profession's recipes an item is used in to its tooltip, with the skill range that still gives points and whether you know the recipe."] = "Ajoute à l'infobulle d'un objet les recettes de ce métier qui l'utilisent, avec la plage de compétence qui rapporte encore des points et si vous connaissez la recette."
L["Also annotates reagents of professions this character does not have (as if at skill 0) - useful to decide what to keep or send to alts."] = "Annote aussi les composants des métiers que ce personnage n'a pas (comme au niveau de compétence 0) - utile pour décider quoi garder ou envoyer à vos rerolls."
L["Always show"] = "Toujours afficher"
L["Author: %s"] = "Auteur : %s"
L["Could not open the settings window on this client. Find the options under Game Menu -> Options -> AddOns -> ProfessionTips."] = "Impossible d'ouvrir la fenêtre des paramètres sur ce client. Les options se trouvent dans Menu du jeu -> Options -> AddOns -> ProfessionTips."
L["Display"] = "Affichage"
L["Include processed materials"] = "Inclure les matériaux transformés"
L["List only recipes this character has already learned. Unlearned recipes still count for the header's accumulated skill range and the '+N more' summary."] = "Ne lister que les recettes déjà apprises par ce personnage. Les recettes non apprises comptent toujours pour la plage de compétence de l'en-tête et le résumé '+N de plus'."
L["more recipes give points"] = "recettes de plus rapportent des points"
L["no skillups"] = "plus aucun point"
L["not learned"] = "non apprise"
L["Only add the tooltip information while this modifier key is held down."] = "N'ajouter les informations à l'infobulle que lorsque cette touche de modification est maintenue enfoncée."
L["Only learned recipes"] = "Recettes apprises uniquement"
L["processed material"] = "matériau transformé"
L["Professions"] = "Métiers"
L["Raw materials also show the recipes of what they are processed into (cloth into bolts, ore into bars, hides into cured hides, ...), marked with 'via'."] = "Les matières premières affichent aussi les recettes de leurs produits transformés (tissu en rouleaux, minerai en barres, peaux en peaux traitées, ...), marquées par 'via'."
L["Recipe lines per profession section. 0 shows only the profession headers with their accumulated skill range; otherwise at least 2 (the lowest- and highest-requirement recipes always appear together). More recipes are summarized as '+N more'."] = "Lignes de recettes par section de métier. 0 n'affiche que les en-têtes de métier avec leur plage de compétence cumulée ; sinon au moins 2 (les recettes aux exigences la plus basse et la plus haute apparaissent toujours ensemble). Les recettes supplémentaires sont résumées en '+N de plus'."
L["Recipes listed per profession"] = "Recettes listées par métier"
L["Show for missing professions"] = "Afficher pour les métiers non appris"
L["Show only while holding"] = "Afficher seulement en maintenant"
L["Version: %s"] = "Version : %s"
L["via %s"] = "via %s"
